// 渲染卡片
function renderCards(items) {
    const grid = document.getElementById('exercise-grid');
    if (items.length === 0) {
        grid.innerHTML = '<div class="empty-state">没有找到匹配的动作</div>';
        return;
    }
    grid.innerHTML = items.map(ex => `
        <div class="card" data-id="${ex.id}">
            <div class="card-img">
                <img src="/media/${ex.gif_url}" alt="${ex.name}" loading="lazy" />
            </div>
            <div class="card-body">
                <div class="card-title">${ex.name}</div>
                <div class="card-meta">
                    <span class="tag">${ex.category}</span>
                    <span class="tag">${ex.target}</span>
                </div>
                <div class="card-equip">🏋️ ${ex.equipment}</div>
            </div>
        </div>
    `).join('');

    grid.querySelectorAll('.card').forEach(card => {
        card.addEventListener('click', () => openDetail(card.dataset.id));
    });
}

// 渲染分页
function renderPagination(total, page, totalPg) {
    document.getElementById('page-info').textContent = `第 ${page} / ${totalPg} 页（共 ${total} 条）`;
    document.getElementById('btn-prev').disabled = page <= 1;
    document.getElementById('btn-next').disabled = page >= totalPg;
}

function goToPage(p) {
    if (p < 1 || p > totalPages) return;
    currentPage = p;
    loadExercises();
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

