    appendChatBubble('user', message);
    input.value = '';

    // 禁用输入
    const sendBtn = document.getElementById('chat-send');
    sendBtn.disabled = true;
    input.disabled = true;
    addTypingIndicator();

    try {
        // exercise_id 放在 URL 路径参数中，请求体只包含 message 和 history
        const isFirst = !exerciseFirstSent.get(currentExerciseId);
        const body = {
            message: message,
            history: isFirst ? [] : history.slice(0, -1),
            is_first: isFirst
        };

        const res = await fetch(`/api/chat/${encodeURIComponent(currentExerciseId)}`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body)
        });

        if (!res.ok) throw new Error(`请求失败: ${res.status}`);

        exerciseFirstSent.set(currentExerciseId, true);
        removeTypingIndicator();

        // 读取 SSE 流
        const reader = res.body.getReader();
        const decoder = new TextDecoder();
        let assistantContent = '';
        const assistantBubble = appendChatBubble('assistant', '');
        const pEl = assistantBubble.querySelector('p');
        let buffer = '';
        let hasError = false;

        while (true) {
            const { done, value } = await reader.read();
            if (done) break;
            buffer += decoder.decode(value, { stream: true });

            // 解析 SSE 事件
            const lines = buffer.split('\n');
            buffer = lines.pop() || '';
            for (const line of lines) {
                if (line.startsWith('data: ')) {
                    const data = line.slice(6);
                    if (data === '[DONE]') continue;
                    try {
                        const parsed = JSON.parse(data);
                        // 优先处理错误信息
                        if (parsed.error) {
                            assistantContent = String(parsed.error);
                            pEl.textContent = assistantContent;
                            hasError = true;
                            break;
                        }
                        if (parsed.content) {
                            assistantContent += parsed.content;
                            pEl.textContent = assistantContent;
                        }
                    } catch (e) {
                        // 忽略解析错误
                    }
                }
            }
            if (hasError) break;
            const container = document.getElementById('chat-messages');
            container.scrollTop = container.scrollHeight;
        }

        // 仅在无错误且助手有内容时记录历史
        if (!hasError && assistantContent) {
            history.push({ role: 'assistant', content: assistantContent });
        }

    } catch (e) {
        removeTypingIndicator();
        appendChatBubble('assistant', '抱歉，出了点问题，请稍后再试。');
        console.error('聊天请求失败', e);
    } finally {
        sendBtn.disabled = false;
        input.disabled = false;
        input.focus();
    }
}

